import React, { useState, useEffect } from 'react';
import axios from 'axios';
import VideoCallIcon from '@mui/icons-material/VideoCall';
import CallIcon from '@mui/icons-material/Call';
import VolumeUpIcon from '@mui/icons-material/VolumeUp';
import VolumeDownIcon from '@mui/icons-material/VolumeDown';
import VolumeOffIcon from '@mui/icons-material/VolumeOff';
import WindowIcon from '@mui/icons-material/Window';
import '../assets/styles/MicrosoftTeams.css';

const MicrosoftTeams = () => {
  const [contacts, setContacts] = useState([]);
  const [showContacts, setShowContacts] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loadingContacts, setLoadingContacts] = useState(false);

  // Verificăm autentificarea la încărcarea paginii
  useEffect(() => {
    checkAuthentication();
  }, []);

  // Verifică starea autentificării
  const checkAuthentication = async () => {
    try {
      const response = await axios.get('/shortcuts/teams/auth/status/');
      setIsAuthenticated(response.data.isAuthenticated);
    } catch (error) {
      console.error('Error checking authentication:', error);
    }
  };

  // Redirecționează utilizatorul către login
  const handleLogin = () => {
    window.location.href = '/teams/login/'; // URL pentru login
  };

  // Preluăm contactele după autentificare
  const fetchContacts = async () => {
    if (!isAuthenticated) {
      console.log("Utilizatorul nu este autentificat.");
      return;
    }

    setLoadingContacts(true);
    try {
      const response = await axios.get('/teams/contacts/'); // Endpoint pentru obținerea contactelor
      setContacts(response.data.contacts); // Stochează contactele
    } catch (error) {
      console.error('There was an error fetching the contacts!', error);
    } finally {
      setLoadingContacts(false);
    }
  };

  // Afișează/ascunde contactele
  const handleToggleContacts = () => {
    if (!isAuthenticated) {
      alert("Trebuie să te autentifici pentru a accesa contactele.");
      return;
    }

    setShowContacts(!showContacts);
    if (!showContacts) {
      fetchContacts();
    }
  };

  // Activează fereastra Microsoft Teams
  const handleActivateTeams = () => {
    axios.post('/shortcuts/teams/activate-teams/')
      .then(response => {
        console.log(response.data.message || 'Microsoft Teams activated successfully');
      })
      .catch(error => {
        console.error('There was an error activating Microsoft Teams!', error);
      });
  };

  // Controlează volumul
  const handleIncreaseVolume = () => {
    axios.post('/shortcuts/teams/increase-volume/')
      .then(response => {
        console.log(response.data.message || 'Volume increased');
      })
      .catch(error => {
        console.error('There was an error increasing the volume!', error);
      });
  };

  const handleDecreaseVolume = () => {
    axios.post('/shortcuts/teams/decrease-volume/')
      .then(response => {
        console.log(response.data.message || 'Volume decreased');
      })
      .catch(error => {
        console.error('There was an error decreasing the volume!', error);
      });
  };

  const handleMute = () => {
    axios.post('/shortcuts/teams/mute-volume/')
      .then(response => {
        console.log(response.data.message || 'Muted');
      })
      .catch(error => {
        console.error('There was an error muting the sound!', error);
      });
  };

  // Inițiază apel video/audio
  const handleVideoCall = (contact) => {
    axios.post('/shortcuts/teams/video-call/', { userId: contact.id })
      .then(response => {
        console.log('Video call initiated:', response.data);
      })
      .catch(error => {
        console.error('There was an error initiating the video call!', error);
      });
  };

  const handleAudioCall = (contact) => {
    axios.post('/shortcuts/teams/audio-call/', { userId: contact.id })
      .then(response => {
        console.log('Audio call initiated:', response.data);
      })
      .catch(error => {
        console.error('There was an error initiating the audio call!', error);
      });
  };

  return (
    <div className="teams-container">
      <h1 className="title">Microsoft Teams</h1>

      {!isAuthenticated ? (
        <button onClick={handleLogin} className="button">
          Conectare la Microsoft Teams
        </button>
      ) : (
        <div className="button-row">
          <button onClick={handleToggleContacts} className="button show-contacts-button">
            {showContacts ? 'Ascunde Contactele' : 'Afișează Contactele'}
          </button>
          <button onClick={handleActivateTeams} className="button">
            <WindowIcon />
          </button>
          <button onClick={handleIncreaseVolume} className="button">
            <VolumeUpIcon />
          </button>
          <button onClick={handleDecreaseVolume} className="button">
            <VolumeDownIcon />
          </button>
          <button onClick={handleMute} className="button">
            <VolumeOffIcon />
          </button>
        </div>
      )}

      {loadingContacts && <p>Se încarcă contactele...</p>}

      {showContacts && (
        <div className="contacts-list">
          <h2>Contacts</h2>
          <ul>
            {contacts.map(contact => (
              <li key={contact.id} className="contact-item">
                <img src={`/shortcuts/teams/contacts/${contact.id}/photo`} 
                  alt={contact.displayName} 
                  className="contact-photo" 
                  onError={(e) => { e.target.src = '/path-to-placeholder-image.png'; }} // Imagine placeholder la eroare
                />
                <span>{contact.displayName}</span>
                <div className="call-buttons">
                  <button onClick={() => handleVideoCall(contact)} className="call-button">
                    <VideoCallIcon />
                  </button>
                  <button onClick={() => handleAudioCall(contact)} className="call-button">
                    <CallIcon />
                  </button>
                </div>
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
};

export default MicrosoftTeams;
